INSERT INTO site_content (id, content) VALUES ('index.pontoon.intro.text', 'Million dollar houses. Million dollar yachts. The Assateague Wild Horses. Dolphins. Restaurants. Marinas. Vibes. Pull the boat up on the Assateague beaches and explore, hit OC''s hottest sandbars and party, or just cruise the Bay and take it easy. <strong>Either way, we got you.</strong>') ON CONFLICT (id) DO UPDATE SET content = 'Million dollar houses. Million dollar yachts. The Assateague Wild Horses. Dolphins. Restaurants. Marinas. Vibes. Pull the boat up on the Assateague beaches and explore, hit OC''s hottest sandbars and party, or just cruise the Bay and take it easy. <strong>Either way, we got you.</strong>', updated_at = now();
