INSERT INTO site_content (id, content) VALUES ('index.review1.text', '“First time jet skiing… it''s love at first ride!! Jayden, Bryan and the team were very nice, helpful and accommodating. Was able to rent 2 jet skis last min and had a blast. If in the area and want good fun for your money I''d recommend OCA Watersports, you won''t be disappointed!!”') ON CONFLICT (id) DO UPDATE SET content = '“First time jet skiing… it''s love at first ride!! Jayden, Bryan and the team were very nice, helpful and accommodating. Was able to rent 2 jet skis last min and had a blast. If in the area and want good fun for your money I''d recommend OCA Watersports, you won''t be disappointed!!”', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('index.review1.author', '— Stewart M.') ON CONFLICT (id) DO UPDATE SET content = '— Stewart M.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('index.review2.text', '“The 6 mile ride was absolutely incredible. No other jet ski place in OC even comes close. You actually get to RIDE, not just go in circles. We saw dolphins and got to cruise by Assateague. Already booked again for next weekend.”') ON CONFLICT (id) DO UPDATE SET content = '“The 6 mile ride was absolutely incredible. No other jet ski place in OC even comes close. You actually get to RIDE, not just go in circles. We saw dolphins and got to cruise by Assateague. Already booked again for next weekend.”', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('index.review2.author', '— Jessica T.') ON CONFLICT (id) DO UPDATE SET content = '— Jessica T.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('index.review3.text', '“Rented a pontoon for my family reunion and it was the best decision we made all trip. Pulled up to Assateague, saw the wild horses, and hit a sandbar on the way back. The kids are STILL talking about it.”') ON CONFLICT (id) DO UPDATE SET content = '“Rented a pontoon for my family reunion and it was the best decision we made all trip. Pulled up to Assateague, saw the wild horses, and hit a sandbar on the way back. The kids are STILL talking about it.”', updated_at = now();
