INSERT INTO site_content (id, content) VALUES ('jetskis.difference.title', 'This Isn''t Your Average Jet Ski Rental.') ON CONFLICT (id) DO UPDATE SET content = 'This Isn''t Your Average Jet Ski Rental.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.difference.text', 'While other Ocean City companies keep you circling the bay in a confined, buoyed-off zone — we take you on an adventure. From the inlet, you ride 6 miles down to the Verrazano Bridge along Assateague Island National Seashore — one of the longest open-water jet ski routes on the East Coast.') ON CONFLICT (id) DO UPDATE SET content = 'While other Ocean City companies keep you circling the bay in a confined, buoyed-off zone — we take you on an adventure. From the inlet, you ride 6 miles down to the Verrazano Bridge along Assateague Island National Seashore — one of the longest open-water jet ski routes on the East Coast.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.difference.text2', 'Our signature <strong>6 Mile Ride</strong> takes you straight past wild horses that have roamed since the 1600s, dolphins breaking the surface off the bow, and sandbars rising out of nowhere. You get <strong>70 minutes</strong> on the water, not 60. Because we ride too, and we know what riders actually want.') ON CONFLICT (id) DO UPDATE SET content = 'Our signature <strong>6 Mile Ride</strong> takes you straight past wild horses that have roamed since the 1600s, dolphins breaking the surface off the bow, and sandbars rising out of nowhere. You get <strong>70 minutes</strong> on the water, not 60. Because we ride too, and we know what riders actually want.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.difference.text3', 'We built this route. Every other company talking about riding to Assateague is following our lead.') ON CONFLICT (id) DO UPDATE SET content = 'We built this route. Every other company talking about riding to Assateague is following our lead.', updated_at = now();
