INSERT INTO site_content (id, content) VALUES ('jetskis.pricing.highlight', 'You get <strong>70 MINUTES</strong> on the water — not 60. Your time starts the moment you hit the water, not when you arrive at the dock.') ON CONFLICT (id) DO UPDATE SET content = 'You get <strong>70 MINUTES</strong> on the water — not 60. Your time starts the moment you hit the water, not when you arrive at the dock.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.rules.r1', '1–3 riders per ski. <strong>450 lb max weight limit</strong> per ski. Up to 10 skis per slot.') ON CONFLICT (id) DO UPDATE SET content = '1–3 riders per ski. <strong>450 lb max weight limit</strong> per ski. Up to 10 skis per slot.', updated_at = now();
