INSERT INTO site_content (id, content) VALUES ('jetskis.faq.eyebrow', 'Know Before You Go') ON CONFLICT (id) DO UPDATE SET content = 'Know Before You Go', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.title', 'Jet Ski FAQ') ON CONFLICT (id) DO UPDATE SET content = 'Jet Ski FAQ', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.q1', 'How fast do your jet skis go?
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.a1', 'Our Sea-Doo GTX skis are capable of 40–42 mph on open water. Speed depends on conditions, weight, and currents. You have full throttle freedom — we''re not running alongside you telling you to slow down.') ON CONFLICT (id) DO UPDATE SET content = 'Our Sea-Doo GTX skis are capable of 40–42 mph on open water. Speed depends on conditions, weight, and currents. You have full throttle freedom — we''re not running alongside you telling you to slow down.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.q2', 'Where do the jet skis ride?
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.a2', 'Our jet ski route runs south from the inlet along Assateague Island down to the Verrazano Bridge — a 6-mile stretch of wide open water. You''ll ride past wild horses, dolphins, hidden sandbars, and some of the most scenic coastline on the East Coast. This is a one-direction ride south, not a circle — the way jet skiing should be. We brief you on the full route before you launch.') ON CONFLICT (id) DO UPDATE SET content = 'Our jet ski route runs south from the inlet along Assateague Island down to the Verrazano Bridge — a 6-mile stretch of wide open water. You''ll ride past wild horses, dolphins, hidden sandbars, and some of the most scenic coastline on the East Coast. This is a one-direction ride south, not a circle — the way jet skiing should be. We brief you on the full route before you launch.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.q3', 'Does instruction time count toward my ride time?
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.a3', 'No. Your 70 minutes starts the moment you hit the water — not when you walk in the door, not when you sign waivers. That''s why we ask you to arrive 45 minutes before your scheduled time. Show up early, get the full 70.') ON CONFLICT (id) DO UPDATE SET content = 'No. Your 70 minutes starts the moment you hit the water — not when you walk in the door, not when you sign waivers. That''s why we ask you to arrive 45 minutes before your scheduled time. Show up early, get the full 70.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.q4', 'What is the minimum age to rent a jet ski in Ocean City?
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.a4', 'You must be at least 16 years old to operate a ski. Riders under 21 require a parent or guardian present at the time of rental. All riders must sign a liability waiver.') ON CONFLICT (id) DO UPDATE SET content = 'You must be at least 16 years old to operate a ski. Riders under 21 require a parent or guardian present at the time of rental. All riders must sign a liability waiver.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.q5', 'How many people can ride on one jet ski?
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.a5', 'You can absolutely ride with more than one person. Each ski holds 1–3 riders with a <strong>450 lb maximum weight limit</strong> per ski. We have up to 10 skis available per time slot. Coming with a big group? Call us at <a href="tel:4106297433" style="color:var(--color-gold)">410-629-RIDE</a> — we''ll make sure we have what you need.') ON CONFLICT (id) DO UPDATE SET content = 'You can absolutely ride with more than one person. Each ski holds 1–3 riders with a <strong>450 lb maximum weight limit</strong> per ski. We have up to 10 skis available per time slot. Coming with a big group? Call us at <a href="tel:4106297433" style="color:var(--color-gold)">410-629-RIDE</a> — we''ll make sure we have what you need.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.q6', 'Do I need experience to ride a jet ski?
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.a6', 'None required. We give every rider a full orientation at the dock before you launch — controls, safety, boundaries, the route. If you can drive a car, you can ride a jet ski. Most first-timers are flying within 10 minutes.') ON CONFLICT (id) DO UPDATE SET content = 'None required. We give every rider a full orientation at the dock before you launch — controls, safety, boundaries, the route. If you can drive a car, you can ride a jet ski. Most first-timers are flying within 10 minutes.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.q7', 'What should I wear and bring?
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.a7', 'Swimwear, sunscreen (apply before arriving — it washes off fast on the water), and a sense of adventure. We provide life jackets. Leave valuables, car keys, and phones in your vehicle or bring a waterproof case.') ON CONFLICT (id) DO UPDATE SET content = 'Swimwear, sunscreen (apply before arriving — it washes off fast on the water), and a sense of adventure. We provide life jackets. Leave valuables, car keys, and phones in your vehicle or bring a waterproof case.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.q8', 'Are refunds available if I cancel?
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.a8', 'All sales are final. No refunds given. In the rare event that we cancel due to extreme weather or mechanical issues on our end, you''ll receive a full credit to rebook at your convenience.') ON CONFLICT (id) DO UPDATE SET content = 'All sales are final. No refunds given. In the rare event that we cancel due to extreme weather or mechanical issues on our end, you''ll receive a full credit to rebook at your convenience.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.q9', 'Is parking available at your location?
INSERT INTO site_content (id, content) VALUES ('jetskis.faq.a9', 'Yes — there''s parking available right at our location at 12817 Harbor Rd. See our <a href="contact.html" style="color:var(--color-gold)">Contact page</a> for the full directions and parking guide.') ON CONFLICT (id) DO UPDATE SET content = 'Yes — there''s parking available right at our location at 12817 Harbor Rd. See our <a href="contact.html" style="color:var(--color-gold)">Contact page</a> for the full directions and parking guide.', updated_at = now();
