INSERT INTO site_content (id, content) VALUES ('jetskis.cta.sub', 'Book your jet ski today. Slots fill fast in peak season — and there''s nothing like this anywhere else in Ocean City, MD.') ON CONFLICT (id) DO UPDATE SET content = 'Book your jet ski today. Slots fill fast in peak season — and there''s nothing like this anywhere else in Ocean City, MD.', updated_at = now();
