INSERT INTO site_content (id, content) VALUES ('pontoons.charter.title', 'Your Boat. Your Rules.') ON CONFLICT (id) DO UPDATE SET content = 'Your Boat. Your Rules.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.charter.text1', 'This isn''t a tour. There''s no captain telling you where to go or how long to stay. You rent the boat — the whole thing, just for your group — and you captain your own adventure across Ocean City Maryland''s entire bay.') ON CONFLICT (id) DO UPDATE SET content = 'This isn''t a tour. There''s no captain telling you where to go or how long to stay. You rent the boat — the whole thing, just for your group — and you captain your own adventure across Ocean City Maryland''s entire bay.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.charter.text2', 'Want to <strong>beach directly on Assateague Island</strong> and let the wild horses walk up to you? Do it. Want to <strong>bar hop to Seacrets or Fish Tales</strong> from the water like a local? Pull up and dock. Want to drop anchor on a sandbar and make it a full-day party in the sun? That''s the most popular move on the bay all summer.') ON CONFLICT (id) DO UPDATE SET content = 'Want to <strong>beach directly on Assateague Island</strong> and let the wild horses walk up to you? Do it. Want to <strong>bar hop to Seacrets or Fish Tales</strong> from the water like a local? Pull up and dock. Want to drop anchor on a sandbar and make it a full-day party in the sun? That''s the most popular move on the bay all summer.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.charter.text3', 'The Assateague Island shoreline is a 37-mile protected National Seashore. Pull your pontoon right up to the bay-side sandbars — some just inches deep. No parking lot. No boardwalk. Just you, the wild horses, and one of the most untouched stretches of coastline on the East Coast.') ON CONFLICT (id) DO UPDATE SET content = 'The Assateague Island shoreline is a 37-mile protected National Seashore. Pull your pontoon right up to the bay-side sandbars — some just inches deep. No parking lot. No boardwalk. Just you, the wild horses, and one of the most untouched stretches of coastline on the East Coast.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.charter.text4', '<strong>Other boat rental companies won''t let you go to Assateague.</strong> That''s exactly why we''re different.') ON CONFLICT (id) DO UPDATE SET content = '<strong>Other boat rental companies won''t let you go to Assateague.</strong> That''s exactly why we''re different.', updated_at = now();
