INSERT INTO site_content (id, content) VALUES ('pontoons.feature1.text', 'Pull your boat right up to the sand on the bay side of Assateague Island National Seashore. The wild horses may walk straight up to you. No other OC rental lets you do this.') ON CONFLICT (id) DO UPDATE SET content = 'Pull your boat right up to the sand on the bay side of Assateague Island National Seashore. The wild horses may walk straight up to you. No other OC rental lets you do this.', updated_at = now();
