INSERT INTO site_content (id, content) VALUES ('pontoons.feature2.text', 'Add on our fishing or crabbing package and make it a full-day experience. The bay between Ocean City and Assateague Island is some of the best crabbing on the Eastern Shore.') ON CONFLICT (id) DO UPDATE SET content = 'Add on our fishing or crabbing package and make it a full-day experience. The bay between Ocean City and Assateague Island is some of the best crabbing on the Eastern Shore.', updated_at = now();
