INSERT INTO site_content (id, content) VALUES ('pontoons.feature3.text', 'Bring your own cooler, snacks, and beverages. The driver stays sober — everyone else can enjoy the ride. Ocean City''s best floating party is the one you bring yourself.') ON CONFLICT (id) DO UPDATE SET content = 'Bring your own cooler, snacks, and beverages. The driver stays sober — everyone else can enjoy the ride. Ocean City''s best floating party is the one you bring yourself.', updated_at = now();
