INSERT INTO site_content (id, content) VALUES ('pontoons.feature4.text', 'Dock at Seacrets, Fish Tales, or Fager''s Island from the water like a local. Pull right up to Ocean City''s most iconic waterfront spots without fighting for parking.') ON CONFLICT (id) DO UPDATE SET content = 'Dock at Seacrets, Fish Tales, or Fager''s Island from the water like a local. Pull right up to Ocean City''s most iconic waterfront spots without fighting for parking.', updated_at = now();
