INSERT INTO site_content (id, content) VALUES ('pontoons.feature5.text', 'Anchor near Assateague Island and watch the famous horses roam the beach. They''ve been free since the 1600s. Seeing them from the water is an experience that doesn''t exist anywhere else.') ON CONFLICT (id) DO UPDATE SET content = 'Anchor near Assateague Island and watch the famous horses roam the beach. They''ve been free since the 1600s. Seeing them from the water is an experience that doesn''t exist anywhere else.', updated_at = now();
