INSERT INTO site_content (id, content) VALUES ('pontoons.faq.title', 'Pontoon Boat FAQ') ON CONFLICT (id) DO UPDATE SET content = 'Pontoon Boat FAQ', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.q1', 'Who drives the boat?
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.a1', 'You do. The renter must be 21+ with a valid driver''s license. We issue a temporary boater''s license at the dock during your orientation. No prior boating experience required — we''ll walk you through everything before you leave the dock.') ON CONFLICT (id) DO UPDATE SET content = 'You do. The renter must be 21+ with a valid driver''s license. We issue a temporary boater''s license at the dock during your orientation. No prior boating experience required — we''ll walk you through everything before you leave the dock.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.q2', 'Can we bring our own food and drinks?
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.a2', 'Absolutely. Bring your cooler, food, and beverages. The driver must remain completely sober for the entire rental. Passengers 21+ are welcome to enjoy drinks responsibly. Think of it like driving a car — same rules apply on the water.') ON CONFLICT (id) DO UPDATE SET content = 'Absolutely. Bring your cooler, food, and beverages. The driver must remain completely sober for the entire rental. Passengers 21+ are welcome to enjoy drinks responsibly. Think of it like driving a car — same rules apply on the water.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.q3', 'What''s the maximum capacity?
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.a3', '12 people maximum per boat. Weight limit is 1,900–2,100 lb total (including people, coolers, and gear). This is Maryland maritime law — no exceptions can be made. Count your group and gear before you book.') ON CONFLICT (id) DO UPDATE SET content = '12 people maximum per boat. Weight limit is 1,900–2,100 lb total (including people, coolers, and gear). This is Maryland maritime law — no exceptions can be made. Count your group and gear before you book.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.q4', 'Where exactly can we take the pontoon?
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.a4', 'The entire bay is yours — from the Verrazano Bridge to the Rt. 90 Bridge. Beach on Assateague Island''s bay-side sandbars, cruise to Seacrets, Fish Tales, or Fager''s Island, drop anchor on a sandbar, or just explore. We give you a full briefing at the dock including route suggestions and must-see spots.') ON CONFLICT (id) DO UPDATE SET content = 'The entire bay is yours — from the Verrazano Bridge to the Rt. 90 Bridge. Beach on Assateague Island''s bay-side sandbars, cruise to Seacrets, Fish Tales, or Fager''s Island, drop anchor on a sandbar, or just explore. We give you a full briefing at the dock including route suggestions and must-see spots.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.q5', 'Can we fish and crab from the boat?
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.a5', 'Yes! Add our fishing or crabbing package when you book. The packages include gear — you just need a valid Maryland fishing or crabbing license, which are available at local tackle shops around Ocean City MD before you arrive at our dock.') ON CONFLICT (id) DO UPDATE SET content = 'Yes! Add our fishing or crabbing package when you book. The packages include gear — you just need a valid Maryland fishing or crabbing license, which are available at local tackle shops around Ocean City MD before you arrive at our dock.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.q6', 'Do we need boating experience?
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.a6', 'No. We provide a full dock orientation covering navigation, safety rules, operating the boat, and what to do if you have a question out on the water. The bay is calm and the pontoon is easy to handle. First-timers do this every day.') ON CONFLICT (id) DO UPDATE SET content = 'No. We provide a full dock orientation covering navigation, safety rules, operating the boat, and what to do if you have a question out on the water. The bay is calm and the pontoon is easy to handle. First-timers do this every day.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.q7', 'How do we get to Assateague Island by boat?
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.a7', 'You beach the pontoon directly on the bay-side of Assateague Island — no parking lot, no trail, no ferry. Just pull up to the shallow sandbars, cut the engine, step off into ankle-deep water, and you''re on one of the most beautiful stretches of coastline on the East Coast. We''ll show you exactly where to go in your briefing.') ON CONFLICT (id) DO UPDATE SET content = 'You beach the pontoon directly on the bay-side of Assateague Island — no parking lot, no trail, no ferry. Just pull up to the shallow sandbars, cut the engine, step off into ankle-deep water, and you''re on one of the most beautiful stretches of coastline on the East Coast. We''ll show you exactly where to go in your briefing.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.q8', 'Is alcohol allowed on the pontoon boat?
INSERT INTO site_content (id, content) VALUES ('pontoons.faq.a8', 'Passengers may consume alcohol. The driver must remain completely sober — this is the same as operating a motor vehicle under Maryland law. We reserve the right to administer a breathalyzer test at any point. Violations end the rental immediately with no refund.') ON CONFLICT (id) DO UPDATE SET content = 'Passengers may consume alcohol. The driver must remain completely sober — this is the same as operating a motor vehicle under Maryland law. We reserve the right to administer a breathalyzer test at any point. Violations end the rental immediately with no refund.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.cta.eyebrow', 'Your Perfect Day Starts Here') ON CONFLICT (id) DO UPDATE SET content = 'Your Perfect Day Starts Here', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.cta.title', 'Your Perfect Day on the Water.') ON CONFLICT (id) DO UPDATE SET content = 'Your Perfect Day on the Water.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('pontoons.cta.sub', 'Call to reserve your pontoon — slots go fast in season. April bookings: call us directly for availability.') ON CONFLICT (id) DO UPDATE SET content = 'Call to reserve your pontoon — slots go fast in season. April bookings: call us directly for availability.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.sticky.text', 'You''ve Read About It. Now Ride It.') ON CONFLICT (id) DO UPDATE SET content = 'You''ve Read About It. Now Ride It.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.hero.eyebrow', 'OCA Watersports Signature Experience') ON CONFLICT (id) DO UPDATE SET content = 'OCA Watersports Signature Experience', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.hero.title', 'The 6 Mile<br>Ride') ON CONFLICT (id) DO UPDATE SET content = 'The 6 Mile<br>Ride', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.hero.sub', 'Ocean City MD → Assateague Island National Seashore') ON CONFLICT (id) DO UPDATE SET content = 'Ocean City MD → Assateague Island National Seashore', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.hero.lead', 'The most talked-about jet ski experience on the East Coast. Wild horses. Dolphins. Open ocean. We didn''t just name it — we built it.') ON CONFLICT (id) DO UPDATE SET content = 'The most talked-about jet ski experience on the East Coast. Wild horses. Dolphins. Open ocean. We didn''t just name it — we built it.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.origin.eyebrow', 'The Origin') ON CONFLICT (id) DO UPDATE SET content = 'The Origin', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.origin.title', 'Where OCA Watersports Earned Its Reputation.') ON CONFLICT (id) DO UPDATE SET content = 'Where OCA Watersports Earned Its Reputation.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.origin.p1', 'It started in 2010. While every other jet ski rental company in Ocean City Maryland was keeping riders locked in a buoyed-off bay circle, we were thinking about what a real ride could look like. Open water. Real distance. Something worth remembering.') ON CONFLICT (id) DO UPDATE SET content = 'It started in 2010. While every other jet ski rental company in Ocean City Maryland was keeping riders locked in a buoyed-off bay circle, we were thinking about what a real ride could look like. Open water. Real distance. Something worth remembering.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.origin.p2', 'We mapped the bay. We scouted the route from our dock at 12817 Harbor Rd all the way to Assateague Island National Seashore — a 6 mile stretch of water that passed sandbars, million-dollar waterfront homes, open bay, and ended at one of the most protected, untouched shorelines in the entire country.') ON CONFLICT (id) DO UPDATE SET content = 'We mapped the bay. We scouted the route from our dock at 12817 Harbor Rd all the way to Assateague Island National Seashore — a 6 mile stretch of water that passed sandbars, million-dollar waterfront homes, open bay, and ended at one of the most protected, untouched shorelines in the entire country.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.origin.p3', 'We called it the <strong>6 Mile Ride</strong>. We gave riders 70 minutes — not 60 — because we ride too, and we knew what that extra 10 minutes meant out there.') ON CONFLICT (id) DO UPDATE SET content = 'We called it the <strong>6 Mile Ride</strong>. We gave riders 70 minutes — not 60 — because we ride too, and we knew what that extra 10 minutes meant out there.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.origin.p4', 'Every other company in Ocean City that talks about riding to Assateague today? They''re following our lead. <strong>We built this route.</strong>') ON CONFLICT (id) DO UPDATE SET content = 'Every other company in Ocean City that talks about riding to Assateague today? They''re following our lead. <strong>We built this route.</strong>', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.origin.pullquote', '"We created the 6 Mile Ride. The unequal watersports rental company — where being equal isn''t good enough."') ON CONFLICT (id) DO UPDATE SET content = '"We created the 6 Mile Ride. The unequal watersports rental company — where being equal isn''t good enough."', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.route.eyebrow', 'The Route') ON CONFLICT (id) DO UPDATE SET content = 'The Route', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.route.title', '6 Miles. 6 Stops.') ON CONFLICT (id) DO UPDATE SET content = '6 Miles. 6 Stops.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.route.sub', 'From our dock in downtown Ocean City MD to the wild shoreline of Assateague Island National Seashore. Here''s every stop along the way.') ON CONFLICT (id) DO UPDATE SET content = 'From our dock in downtown Ocean City MD to the wild shoreline of Assateague Island National Seashore. Here''s every stop along the way.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop1.num', 'Stop 01 · The Launch') ON CONFLICT (id) DO UPDATE SET content = 'Stop 01 · The Launch', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop1.title', 'Our Dock — Downtown Ocean City') ON CONFLICT (id) DO UPDATE SET content = 'Our Dock — Downtown Ocean City', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop1.dist', '📍 12817 Harbor Rd, Ocean City MD') ON CONFLICT (id) DO UPDATE SET content = '📍 12817 Harbor Rd, Ocean City MD', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop1.text', 'You arrive at our dock at 12817 Harbor Rd — right on the bay with direct water access and the biggest riding area in OC. Orientation. Waivers. Briefing on the route south to Assateague. Then you launch.') ON CONFLICT (id) DO UPDATE SET content = 'You arrive at our dock at 12817 Harbor Rd — right on the bay with direct water access and the biggest riding area in OC. Orientation. Waivers. Briefing on the route south to Assateague. Then you launch.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop2.num', 'Stop 02 · The Open Bay') ON CONFLICT (id) DO UPDATE SET content = 'Stop 02 · The Open Bay', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop2.title', 'Full Throttle Freedom') ON CONFLICT (id) DO UPDATE SET content = 'Full Throttle Freedom', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop2.dist', '🌊 Largest riding area in Ocean City MD') ON CONFLICT (id) DO UPDATE SET content = '🌊 Largest riding area in Ocean City MD', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop2.text', 'Within minutes of launch you''re heading south into wide open water — 6 miles of bay stretching along Assateague Island all the way to the Verrazano Bridge. No circles. No buoys. No other company gives you this. Hit the throttle and ride. Million-dollar waterfront homes line the shore. The coastline of Assateague opens up ahead. This is the ride.') ON CONFLICT (id) DO UPDATE SET content = 'Within minutes of launch you''re heading south into wide open water — 6 miles of bay stretching along Assateague Island all the way to the Verrazano Bridge. No circles. No buoys. No other company gives you this. Hit the throttle and ride. Million-dollar waterfront homes line the shore. The coastline of Assateague opens up ahead. This is the ride.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop3.num', 'Stop 03 · The Sandbars') ON CONFLICT (id) DO UPDATE SET content = 'Stop 03 · The Sandbars', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop3.title', 'The OC Sandbars') ON CONFLICT (id) DO UPDATE SET content = 'The OC Sandbars', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop3.dist', '🏖️ Shallow-water carving ground') ON CONFLICT (id) DO UPDATE SET content = '🏖️ Shallow-water carving ground', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop3.text', 'As you approach Assateague Island, shallow sandbars rise from the bay floor — some just inches deep. Cut through them. Slow down and drift across them. Pontoon riders beach here. Jet ski riders carve circles. This is where Ocean City''s summer crowd completely disappears.') ON CONFLICT (id) DO UPDATE SET content = 'As you approach Assateague Island, shallow sandbars rise from the bay floor — some just inches deep. Cut through them. Slow down and drift across them. Pontoon riders beach here. Jet ski riders carve circles. This is where Ocean City''s summer crowd completely disappears.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop4.num', 'Stop 04 · Assateague Island Coastline') ON CONFLICT (id) DO UPDATE SET content = 'Stop 04 · Assateague Island Coastline', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop4.title', 'The National Seashore') ON CONFLICT (id) DO UPDATE SET content = 'The National Seashore', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop4.dist', '🌿 37 miles of federally protected wilderness') ON CONFLICT (id) DO UPDATE SET content = '🌿 37 miles of federally protected wilderness', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop4.text', 'You arrive at Assateague Island National Seashore — a 37-mile barrier island with zero development. No hotels. No condos. Just wild beach, barrier dunes, and the Atlantic. The contrast from Ocean City just 6 miles behind you is staggering. Protected by the National Park Service since 1965.') ON CONFLICT (id) DO UPDATE SET content = 'You arrive at Assateague Island National Seashore — a 37-mile barrier island with zero development. No hotels. No condos. Just wild beach, barrier dunes, and the Atlantic. The contrast from Ocean City just 6 miles behind you is staggering. Protected by the National Park Service since 1965.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop5.num', 'Stop 05 · Wild Horse Territory') ON CONFLICT (id) DO UPDATE SET content = 'Stop 05 · Wild Horse Territory', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop5.title', 'The Wild Horses') ON CONFLICT (id) DO UPDATE SET content = 'The Wild Horses', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop5.dist', '🐴 Free since the 1600s') ON CONFLICT (id) DO UPDATE SET content = '🐴 Free since the 1600s', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop5.text', 'The famous wild Assateague horses have roamed this island for over 400 years. Legend says they swam ashore from a Spanish shipwreck in the 1500s. Whether true or not, seeing them on the beach — from the water, from your jet ski — is a moment that doesn''t exist anywhere else in the world quite like this.') ON CONFLICT (id) DO UPDATE SET content = 'The famous wild Assateague horses have roamed this island for over 400 years. Legend says they swam ashore from a Spanish shipwreck in the 1500s. Whether true or not, seeing them on the beach — from the water, from your jet ski — is a moment that doesn''t exist anywhere else in the world quite like this.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop6.num', 'Stop 06 · The Return') ON CONFLICT (id) DO UPDATE SET content = 'Stop 06 · The Return', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop6.title', 'Sunset on the Bay') ON CONFLICT (id) DO UPDATE SET content = 'Sunset on the Bay', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop6.dist', '🌅 The best view of Ocean City, Maryland') ON CONFLICT (id) DO UPDATE SET content = '🌅 The best view of Ocean City, Maryland', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.stop6.text', 'You turn back toward the OC skyline with the sun dropping behind it and the bay going glassy. This is the most photographed part of the ride — riders slow down here on instinct. You''ve just done something that most people visiting Ocean City never even know exists. See you back at the dock.') ON CONFLICT (id) DO UPDATE SET content = 'You turn back toward the OC skyline with the sun dropping behind it and the bay going glassy. This is the most photographed part of the ride — riders slow down here on instinct. You''ve just done something that most people visiting Ocean City never even know exists. See you back at the dock.', updated_at = now();
