INSERT INTO site_content (id, content) VALUES ('6mile.map.title', 'The Interactive 6 Mile Ride') ON CONFLICT (id) DO UPDATE SET content = 'The Interactive 6 Mile Ride', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.map.sub', 'Every stop. Every view. Every moment. Explore the full route on our satellite map loaded with photos and videos from the actual ride.') ON CONFLICT (id) DO UPDATE SET content = 'Every stop. Every view. Every moment. Explore the full route on our satellite map loaded with photos and videos from the actual ride.', updated_at = now();
