INSERT INTO site_content (id, content) VALUES ('6mile.review1.text', 'The 6 mile ride was absolutely incredible. No other jet ski place in OC even comes close. You actually get to RIDE, not just go in circles. We saw dolphins and got to cruise by Assateague. Already booked again for next weekend.') ON CONFLICT (id) DO UPDATE SET content = 'The 6 mile ride was absolutely incredible. No other jet ski place in OC even comes close. You actually get to RIDE, not just go in circles. We saw dolphins and got to cruise by Assateague. Already booked again for next weekend.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.review1.author', '— Jessica T. · Ocean City, MD') ON CONFLICT (id) DO UPDATE SET content = '— Jessica T. · Ocean City, MD', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.review2.text', 'We''ve been coming to Ocean City for 15 years and this was the most unique thing we''ve ever done here. The route to Assateague, seeing the wild horses from the water — we had no idea this even existed. OCA is in a class by themselves.') ON CONFLICT (id) DO UPDATE SET content = 'We''ve been coming to Ocean City for 15 years and this was the most unique thing we''ve ever done here. The route to Assateague, seeing the wild horses from the water — we had no idea this even existed. OCA is in a class by themselves.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.review2.author', '— The Mercer Family · Annapolis, MD') ON CONFLICT (id) DO UPDATE SET content = '— The Mercer Family · Annapolis, MD', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('6mile.review3.text', '70 minutes feels like the right amount of time — 60 would have felt rushed. The 6 mile route is the real deal. Wide open water, the horses on the beach, sandbars you can carve through. Best watersports experience I''ve had anywhere on the East Coast.') ON CONFLICT (id) DO UPDATE SET content = '70 minutes feels like the right amount of time — 60 would have felt rushed. The 6 mile route is the real deal. Wide open water, the horses on the beach, sandbars you can carve through. Best watersports experience I''ve had anywhere on the East Coast.', updated_at = now();
