INSERT INTO site_content (id, content) VALUES ('6mile.cta.sub', 'The 6 Mile Ride is our signature experience — and it''s included in every single jet ski rental. You don''t pay extra for the best ride in Ocean City Maryland. You just book and show up.') ON CONFLICT (id) DO UPDATE SET content = 'The 6 Mile Ride is our signature experience — and it''s included in every single jet ski rental. You don''t pay extra for the best ride in Ocean City Maryland. You just book and show up.', updated_at = now();
