INSERT INTO site_content (id, content) VALUES ('about.story.eyebrow', 'The Story') ON CONFLICT (id) DO UPDATE SET content = 'The Story', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.story.title', 'Founded on One Idea:<br>Give People a Real Adventure.') ON CONFLICT (id) DO UPDATE SET content = 'Founded on One Idea:<br>Give People a Real Adventure.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.story.p1', 'We started OCA Watersports in 2010 with a straightforward belief — people deserve better than a 60-minute bay circle. They deserve a real ride. So we gave them one.') ON CONFLICT (id) DO UPDATE SET content = 'We started OCA Watersports in 2010 with a straightforward belief — people deserve better than a 60-minute bay circle. They deserve a real ride. So we gave them one.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.story.p2', 'We mapped the entire bay between Ocean City and Assateague Island. We found the sandbars, the dolphin feeding grounds, the stretch of beach where the wild horses come down to the waterline. We built a 6 mile route that became the signature experience in Ocean City, Maryland — one that no other company has been able to replicate.') ON CONFLICT (id) DO UPDATE SET content = 'We mapped the entire bay between Ocean City and Assateague Island. We found the sandbars, the dolphin feeding grounds, the stretch of beach where the wild horses come down to the waterline. We built a 6 mile route that became the signature experience in Ocean City, Maryland — one that no other company has been able to replicate.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.story.p3', 'Fifteen years later, the mission hasn''t changed. We run the largest riding area in Ocean City. We give riders 70 minutes, not 60. We point out where the horses walk, where the dolphins feed, where the sandbars rise from nowhere at low tide. That ride became the reason thousands of families come back to OCA Watersports year after year.') ON CONFLICT (id) DO UPDATE SET content = 'Fifteen years later, the mission hasn''t changed. We run the largest riding area in Ocean City. We give riders 70 minutes, not 60. We point out where the horses walk, where the dolphins feed, where the sandbars rise from nowhere at low tide. That ride became the reason thousands of families come back to OCA Watersports year after year.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.story.p4', 'We are not a babysitter operation. We trust our riders. We give them the whole bay. And we take genuine pride in being the best watersports company in Ocean City, Maryland — not because we say so, but because 640+ Google reviews do.') ON CONFLICT (id) DO UPDATE SET content = 'We are not a babysitter operation. We trust our riders. We give them the whole bay. And we take genuine pride in being the best watersports company in Ocean City, Maryland — not because we say so, but because 640+ Google reviews do.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.evolution.eyebrow', 'The Evolution') ON CONFLICT (id) DO UPDATE SET content = 'The Evolution', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.evolution.title', 'From Under The Bridge<br>to OCA Watersports') ON CONFLICT (id) DO UPDATE SET content = 'From Under The Bridge<br>to OCA Watersports', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.evolution.p1', 'You might know us as <strong>Under The Bridge Watersports</strong> — that''s how we started. Same team. Same 6 Mile Ride. Same passion for putting people on the water. But we outgrew the name and the location. <strong>OCA</strong> stands for <strong>Ocean City + Assateague</strong> — the two places that define everything we do.') ON CONFLICT (id) DO UPDATE SET content = 'You might know us as <strong>Under The Bridge Watersports</strong> — that''s how we started. Same team. Same 6 Mile Ride. Same passion for putting people on the water. But we outgrew the name and the location. <strong>OCA</strong> stands for <strong>Ocean City + Assateague</strong> — the two places that define everything we do.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.evolution.p2', 'New name. New home at 12817 Harbor Rd. Bigger riding area. More open water. Better access to Assateague Island and everything the bay has to offer. The ride got an upgrade — and so did we.') ON CONFLICT (id) DO UPDATE SET content = 'New name. New home at 12817 Harbor Rd. Bigger riding area. More open water. Better access to Assateague Island and everything the bay has to offer. The ride got an upgrade — and so did we.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.location.eyebrow', 'Find Us') ON CONFLICT (id) DO UPDATE SET content = 'Find Us', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.location.title', 'Right Where You Need to Be.<br>Right in the Heart of the Action.') ON CONFLICT (id) DO UPDATE SET content = 'Right Where You Need to Be.<br>Right in the Heart of the Action.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.location.p1', '12817 Harbor Rd — right on the bay with direct water access and the biggest riding area in all of OC. From our dock, you have a straight shot to Assateague Island, open water, and everything in between.') ON CONFLICT (id) DO UPDATE SET content = '12817 Harbor Rd — right on the bay with direct water access and the biggest riding area in all of OC. From our dock, you have a straight shot to Assateague Island, open water, and everything in between.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.location.p2', 'Pull up, park, walk to the dock, and your adventure begins. No wasted time. No long idle zones. You''re on the water in seconds.') ON CONFLICT (id) DO UPDATE SET content = 'Pull up, park, walk to the dock, and your adventure begins. No wasted time. No long idle zones. You''re on the water in seconds.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.partner.title', 'Ride With Us. Eat Like a Local.') ON CONFLICT (id) DO UPDATE SET content = 'Ride With Us. Eat Like a Local.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('about.partner.text', 'Show your OCA confirmation email at <a href="https://angleroc.net" target="_blank" rel="noopener">12817 Harbor Rd &amp; Bar</a> — directly next door to our dock — and get <strong style="color:var(--color-gold)">10% off your entire food &amp; drinks tab.</strong> One of Ocean City''s most iconic waterfront spots. The kind of lunch or dinner that makes a perfect end to a day on the water.') ON CONFLICT (id) DO UPDATE SET content = 'Show your OCA confirmation email at <a href="https://angleroc.net" target="_blank" rel="noopener">12817 Harbor Rd &amp; Bar</a> — directly next door to our dock — and get <strong style="color:var(--color-gold)">10% off your entire food &amp; drinks tab.</strong> One of Ocean City''s most iconic waterfront spots. The kind of lunch or dinner that makes a perfect end to a day on the water.', updated_at = now();
