INSERT INTO site_content (id, content) VALUES ('about.diff.feature2.text', 'We ride too. We know that 60 minutes isn''t enough to do the 6 mile route justice. So we give you 70, and we start the clock when you hit the water — not when you walk in the door.') ON CONFLICT (id) DO UPDATE SET content = 'We ride too. We know that 60 minutes isn''t enough to do the 6 mile route justice. So we give you 70, and we start the clock when you hit the water — not when you walk in the door.', updated_at = now();
