INSERT INTO site_content (id, content) VALUES ('about.diff.feature3.text', 'Right on the bay in the biggest riding area in OC. You launch and you''re riding. No idle zones, no wasted time. Location matters — ours is unmatched.') ON CONFLICT (id) DO UPDATE SET content = 'Right on the bay in the biggest riding area in OC. You launch and you''re riding. No idle zones, no wasted time. Location matters — ours is unmatched.', updated_at = now();
