INSERT INTO site_content (id, content) VALUES ('about.diff.feature4.text', 'We are not a babysitter operation. We brief you, we trust you, and we give you the whole bay. Ride where you want within our boundaries. No guided circles. No escort boats. Real freedom.') ON CONFLICT (id) DO UPDATE SET content = 'We are not a babysitter operation. We brief you, we trust you, and we give you the whole bay. Ride where you want within our boundaries. No guided circles. No escort boats. Real freedom.', updated_at = now();
