INSERT INTO site_content (id, content) VALUES ('about.diff.feature5.text', 'Established in 2010 and still running strong. Our 640+ Google reviews speak louder than anything we could say. Most of them mention the same things: the route, the staff, and the fact that there''s nothing like this in Ocean City.') ON CONFLICT (id) DO UPDATE SET content = 'Established in 2010 and still running strong. Our 640+ Google reviews speak louder than anything we could say. Most of them mention the same things: the route, the staff, and the fact that there''s nothing like this in Ocean City.', updated_at = now();
