INSERT INTO site_content (id, content) VALUES ('about.diff.feature6.text', 'Jet skis to the island shoreline. Pontoon boats right up onto the bay-side sandbars. Wild horses. Dolphins. A 37-mile protected National Seashore as your backdrop. It exists right here — most people just don''t know to look for it.') ON CONFLICT (id) DO UPDATE SET content = 'Jet skis to the island shoreline. Pontoon boats right up onto the bay-side sandbars. Wild horses. Dolphins. A 37-mile protected National Seashore as your backdrop. It exists right here — most people just don''t know to look for it.', updated_at = now();
