INSERT INTO site_content (id, content) VALUES ('contact.parking.r3', '<strong>Next to Harborside</strong> restaurant — use it as your landmark if GPS gets weird. Our dock is steps from the lot.') ON CONFLICT (id) DO UPDATE SET content = '<strong>Next to Harborside</strong> restaurant — use it as your landmark if GPS gets weird. Our dock is steps from the lot.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('contact.parking.r4', '<strong>Uber / Lyft</strong> recommended on peak summer weekends. Drop off at 12817 Harbor Rd, Ocean City, MD.') ON CONFLICT (id) DO UPDATE SET content = '<strong>Uber / Lyft</strong> recommended on peak summer weekends. Drop off at 12817 Harbor Rd, Ocean City, MD.', updated_at = now();
