INSERT INTO site_content (id, content) VALUES ('contact.faq.q1', 'Where exactly are you located?
INSERT INTO site_content (id, content) VALUES ('contact.faq.a1', 'We''re at 12817 Harbor Rd in Ocean City, Maryland — right on the bay with direct water access. You''ll see our dock and boats from the parking area. Plug the address into GPS and it''ll take you right to us.') ON CONFLICT (id) DO UPDATE SET content = 'We''re at 12817 Harbor Rd in Ocean City, Maryland — right on the bay with direct water access. You''ll see our dock and boats from the parking area. Plug the address into GPS and it''ll take you right to us.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('contact.faq.q2', 'Where do I park?
INSERT INTO site_content (id, content) VALUES ('contact.faq.a2', 'Free parking is available at our location — 12817 Harbor Rd. Street parking is also nearby. On peak summer weekends, consider Uber or Lyft and drop off right at 12817 Harbor Rd.') ON CONFLICT (id) DO UPDATE SET content = 'Free parking is available at our location — 12817 Harbor Rd. Street parking is also nearby. On peak summer weekends, consider Uber or Lyft and drop off right at 12817 Harbor Rd.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('contact.faq.q3', 'How early should I arrive?
INSERT INTO site_content (id, content) VALUES ('contact.faq.a3', 'Please arrive at least <strong>45 minutes before your scheduled ride time</strong> to complete paperwork, sign waivers, and attend your safety orientation. If you arrive late, your time on the water will be reduced — we cannot extend it. Your ride time starts when you hit the water, so protect it by arriving early.') ON CONFLICT (id) DO UPDATE SET content = 'Please arrive at least <strong>45 minutes before your scheduled ride time</strong> to complete paperwork, sign waivers, and attend your safety orientation. If you arrive late, your time on the water will be reduced — we cannot extend it. Your ride time starts when you hit the water, so protect it by arriving early.', updated_at = now();
INSERT INTO site_content (id, content) VALUES ('contact.faq.q4', 'Can I use Uber or Lyft to get there?
INSERT INTO site_content (id, content) VALUES ('contact.faq.a4', 'Absolutely — and it''s a great option on busy summer weekends. Request drop-off at <strong>12817 Harbor Rd, Ocean City, MD</strong>. We''re a short ride from anywhere in town.') ON CONFLICT (id) DO UPDATE SET content = 'Absolutely — and it''s a great option on busy summer weekends. Request drop-off at <strong>12817 Harbor Rd, Ocean City, MD</strong>. We''re a short ride from anywhere in town.', updated_at = now();
